var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MEMBER_HARMONY_NULL_NULL","text":{"KOREA":"아아……! 아아아아아악!!","JPN":"ああ……！　ああああああっ！！","ENG":"Ah...! AAAAAHHHHH!!!","TWN":"啊啊……！啊啊啊啊啊啊！！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"여기 너를 위해 예비된 단두대가 왔으니, 안식에 들도록 하라.","JPN":"ここに貴様のために準備された断頭台がある、安息に入れ。","ENG":"This guillotine has been reserved for you. You shall rest in peace.","TWN":"這是為你而準備的斷頭台，進入安息吧。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MEMBER_HARMONY_NULL_NULL","text":{"KOREA":"후후, 후흐흐흐흐……!","JPN":"ふふ、ふふふふふ……！","ENG":"Hu hu... Hu hu hu hu hu...!","TWN":"呵呵，呵呵呵呵呵……！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MEMBER_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님께서 돌아오셨다……! 그분께서 우리의 염원을……!","JPN":"マエストロがお戻りだ……！　あの方が我々の願いを……！","ENG":"Chief Conductor has returned...! She will grant our wishes–!","TWN":"指揮家回來了……！她會把我們的願望……！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이 침식체들은 전부 유언이 길군요.","JPN":"この侵食体はみんな遺言が長いですね。","ENG":"All these C.O.s talk too much.","TWN":"這些侵蝕體的遺言全都很長啊。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"음성 저장할 공간이 부족하니 곱게 죽어 주는 편이 좋습니다만.","JPN":"音声を保存するための容量が足りないので、大人しく死んでくれるとありがたいのですが。","ENG":"I'm running out of storage for audio, so it'd be nice if they just died without saying anything.","TWN":"保存語音的空間不足，還是死得漂亮點更好。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……핵이 파괴되었으니, 두 번 다시 이 세계에 모습을 비추지는 않을 터.","JPN":"……彼らは核が破壊されている。二度とこの世界に姿を現せまい。","ENG":"Their cores have been destroyed. They will never show their faces on this world again.","TWN":"……她們核心被破壞了，不會再出現在這個世界上了。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"실로 훌륭한 무용이로다.","JPN":"実に素晴らしい武勇だ。","ENG":"An excellent display of valor.","TWN":"你的勇猛無人能敵。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 저장 공간에는 아직 그 시기의 영상이 존재합니다. 침식체.","JPN":"私のメモリには、まだあの頃の映像が存在します。侵食体。","ENG":"I still store the video of that day, C.O.","TWN":"我的存儲空間裡還有那個時期的影像，侵蝕體。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그대의 동료들에 대해서는……","JPN":"そなたの仲間については……","ENG":"About what happened to your colleagues...","TWN":"對於你的同伴……"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그 이상 발언하지 마십시오.","JPN":"それ以上の発言はおやめください。","ENG":"You do not speak anymore.","TWN":"請不要再說下去了。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 당신과 목표 달성을 위해 일시적으로 협조하고 있을 뿐입니다.","JPN":"私はあなたと目標達成のために一時的に協力しているだけです。","ENG":"This is a temporary alliance because our objectives line up.","TWN":"我和你只是為了達成目標，暫時合作而已。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그러니 불필요한 발언은 하지 마십시오.","JPN":"ですので、不要な発言は慎んでください。","ENG":"So avoid making any unnecessary remarks.","TWN":"所以，請不要發表不必要的言論。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이 시점에 적대 관계를 형성하는 행위는 서로에게 비합리적인 선택이 될 것입니다.","JPN":"この時点で敵対関係を形成する行為はお互いに非合理的な選択になるでしょう。","ENG":"Turning me into your enemy at this point will be inefficient for the both of us.","TWN":"在這個時候做出形成敵對關係的行為，對彼此來說都是不合理的選擇。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……알겠다. 그대의 뜻을 존중하지.","JPN":"……よかろう。そなたの意思を尊重しよう。","ENG":"...Understood. I will do as you say.","TWN":"……知道了。我尊重你的意思。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐시기 침식체! 침묵 확인! 이걸로 기분 나쁜 연주랑은 안녕이야!","JPN":"何とか侵食体！　沈黙を確認！　これで気持ち悪い演奏とはおさらばだね！","ENG":"Whatchamacallit C.O.! Kill confirmed! Now it's bye-bye to that creepy music!","TWN":"那個什麼侵蝕體！確認沉默！用這個告別讓人不愉快的演奏吧！"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"레이첼, 평범하게 말하십시오. 교육 받은 오퍼레이터들과 1%도 일치하지 않습니다.","JPN":"レイチェル、普通に話しなさい。教育を受けたオペレーターと1％も一致していません。","ENG":"Rachel, speak normally. Your speech pattern is not even 1% compatible with that of trained operators.","TWN":"瑞秋，請你說話正常點。和其他受訓的領航員連1%都不一樣。"},"stage":{"bg":"DOCK_CLOUDY","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};